import React from 'react';

export default function Dashboard() {
  return (
    <div style={{
      background: '#fff', borderRadius: '12px',
      border: '1px solid #e0e0e0', padding: '20px',
      marginBottom: '0'
    }}>
      <h2 style={{ margin: 0, fontSize: '16px', color: '#666' }}>
        Welcome to CloudDrive ☁️
      </h2>
    </div>
  );
}
